import { useState, useEffect, useRef } from "react";

// ============================================================
// ✏️  EDIT YOUR INFO HERE
// ============================================================
const ME = {
  name:      "Phawat Tanajiranon",
  nickname:  "Beam",
  role:      "Backend Developer",
  tagline:   "Node.js · Python · Systems that scale",
  email:     "beamstary@gmail.com",
  github:    "https://github.com/yourusername",
  linkedin:  "https://linkedin.com/in/yourusername",
  location:  "Bangkok, Thailand",
  arcana:    "THE FOOL",
  about:     "I build robust, scalable backend systems with clean architecture and a passion for performance. From REST APIs to real-time services — I bring ideas to life through code.",
};

// ============================================================
// ✏️  SKILLS — Edit levels and names here
// ============================================================
const SKILLS = {
  backend: {
    label: "Backend Systems", icon: "⬡", arcana: "THE TOWER",
    items: [
      { name: "Node.js / Express", level: 88, tag: "Advanced"     },
      { name: "Python / FastAPI",  level: 82, tag: "Advanced"     },
      { name: "REST API Design",   level: 90, tag: "Expert"       },
      { name: "GraphQL",           level: 70, tag: "Intermediate" },
      { name: "WebSockets",        level: 72, tag: "Intermediate" },
      { name: "Microservices",     level: 68, tag: "Intermediate" },
    ],
  },
  database: {
    label: "Database & Storage", icon: "◈", arcana: "THE HERMIT",
    items: [
      { name: "PostgreSQL",        level: 85, tag: "Advanced"     },
      { name: "MongoDB",           level: 80, tag: "Advanced"     },
      { name: "Redis",             level: 74, tag: "Intermediate" },
      { name: "MySQL",             level: 78, tag: "Intermediate" },
      { name: "Prisma / ORM",      level: 82, tag: "Advanced"     },
      { name: "Database Design",   level: 80, tag: "Advanced"     },
    ],
  },
  devops: {
    label: "DevOps & Tools", icon: "◉", arcana: "THE STAR",
    items: [
      { name: "Git / GitHub",      level: 92, tag: "Expert"       },
      { name: "Docker",            level: 75, tag: "Intermediate" },
      { name: "Linux / Bash",      level: 80, tag: "Advanced"     },
      { name: "AWS / Cloud",       level: 68, tag: "Intermediate" },
      { name: "CI/CD Pipelines",   level: 70, tag: "Intermediate" },
      { name: "Jest / Testing",    level: 76, tag: "Intermediate" },
    ],
  },
};

// ============================================================
// ✏️  EXPERIENCE — Edit your work history here
// ============================================================
const EXP = [
  {
    role:    "Backend Developer",
    company: "Your Company",
    period:  "2023 — Present",
    type:    "Full-time",
    arcana:  "I",
    color:   "#00c8ff",
    desc:    "Designed and maintained scalable REST APIs serving thousands of daily requests. Optimized database queries reducing response time by 45%.",
    tags:    ["Node.js", "PostgreSQL", "Docker", "Redis"],
  },
  {
    role:    "API Engineer",
    company: "Tech Startup",
    period:  "2022 — 2023",
    type:    "Full-time",
    arcana:  "II",
    color:   "#7b61ff",
    desc:    "Built microservice architecture from scratch. Implemented auth systems, rate limiting, and real-time notification services.",
    tags:    ["Python", "FastAPI", "MongoDB", "WebSockets"],
  },
  {
    role:    "Junior Backend Dev",
    company: "Digital Agency",
    period:  "2021 — 2022",
    type:    "Contract",
    arcana:  "III",
    color:   "#ffd700",
    desc:    "Developed backend features for client web apps. Built automated data pipelines and third-party API integrations.",
    tags:    ["Node.js", "MySQL", "REST APIs", "AWS"],
  },
];

// ============================================================
// SVG ASSETS
// ============================================================
const MoonSVG = () => (
  <svg width="120" height="120" viewBox="0 0 120 120" fill="none"
    style={{position:"absolute",opacity:.1,top:"-20px",right:"-20px",pointerEvents:"none"}}>
    <circle cx="60" cy="60" r="50" stroke="#00c8ff" strokeWidth="1"/>
    <path d="M60 10 C35 10 15 32 15 60 C15 88 35 110 60 110 C48 95 42 78 42 60 C42 42 48 25 60 10Z"
      fill="#00c8ff" opacity=".25"/>
  </svg>
);

const Tri = ({ size=40, color="#00c8ff", op=0.3, style={} }) => (
  <svg width={size} height={size} viewBox="0 0 40 40" fill="none"
    style={{...style, opacity:op, pointerEvents:"none"}}>
    <polygon points="20,2 38,36 2,36" stroke={color} strokeWidth="1.5" fill="none"/>
  </svg>
);

// ============================================================
// STYLES
// ============================================================
const CSS = `
@import url('https://fonts.googleapis.com/css2?family=Cinzel:wght@400;600;700;900&family=Rajdhani:wght@300;400;500;600;700&family=Share+Tech+Mono&display=swap');
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
:root{
  --ink:#01060f;--navy:#050d1f;--navy2:#091428;--panel:rgba(5,13,31,0.92);
  --blue:#00c8ff;--blue2:#0088cc;--gold:#ffd700;--purple:#7b61ff;
  --white:#e8f4ff;--muted:#5a7a9a;--dim:#2a4a6a;
  --border:rgba(0,200,255,0.18);--border2:rgba(255,215,0,0.2);
  --glow:0 0 24px rgba(0,200,255,0.5),0 0 80px rgba(0,200,255,0.15);
  --glow-gold:0 0 20px rgba(255,215,0,0.5),0 0 60px rgba(255,215,0,0.1);
  --hd:'Cinzel',serif;--body:'Rajdhani',sans-serif;--mono:'Share Tech Mono',monospace;
  --r:8px;--tr:all 0.32s cubic-bezier(0.4,0,0.2,1);
}
html{scroll-behavior:smooth}
body{background:var(--ink);color:var(--white);font-family:var(--body);overflow-x:hidden;min-height:100vh;cursor:none}
::-webkit-scrollbar{width:3px}::-webkit-scrollbar-track{background:var(--ink)}::-webkit-scrollbar-thumb{background:var(--blue);border-radius:2px}

#p3c{position:fixed;width:14px;height:14px;border:2px solid var(--blue);border-radius:50%;
  pointer-events:none;z-index:9999;transform:translate(-50%,-50%);mix-blend-mode:screen;transition:width .12s,height .12s}
#p3d{position:fixed;width:4px;height:4px;background:var(--blue);border-radius:50%;
  pointer-events:none;z-index:9999;transform:translate(-50%,-50%);mix-blend-mode:screen}

@keyframes fadeUp{from{opacity:0;transform:translateY(26px)}to{opacity:1;transform:translateY(0)}}
@keyframes fadeIn{from{opacity:0}to{opacity:1}}
@keyframes slideR{from{opacity:0;transform:translateX(-28px)}to{opacity:1;transform:translateX(0)}}
@keyframes spin{from{transform:rotate(0deg)}to{transform:rotate(360deg)}}
@keyframes spinR{from{transform:rotate(0deg)}to{transform:rotate(-360deg)}}
@keyframes float{0%,100%{transform:translateY(0) rotate(0deg)}50%{transform:translateY(-13px) rotate(2deg)}}
@keyframes scanH{0%{transform:translateY(-200px)}100%{transform:translateY(120vh)}}
@keyframes moonGlow{0%,100%{filter:drop-shadow(0 0 8px rgba(0,200,255,.5))}50%{filter:drop-shadow(0 0 28px rgba(0,200,255,1))}}
@keyframes pulse{0%,100%{opacity:.5}50%{opacity:1}}
@keyframes barFill{from{width:0}to{width:var(--w)}}
@keyframes borderAnim{0%,100%{opacity:.3}50%{opacity:.8}}

/* BG */
.bg-l{position:fixed;inset:0;z-index:0;pointer-events:none;overflow:hidden}
.bg-g{position:absolute;inset:0;
  background:radial-gradient(ellipse 80% 60% at 15% 0%,rgba(0,100,200,.12) 0%,transparent 60%),
    radial-gradient(ellipse 60% 80% at 85% 100%,rgba(123,97,255,.1) 0%,transparent 60%),
    linear-gradient(180deg,var(--ink) 0%,#020a18 50%,var(--ink) 100%)}
.bg-grid{position:absolute;inset:0;
  background-image:linear-gradient(rgba(0,200,255,.038) 1px,transparent 1px),
    linear-gradient(90deg,rgba(0,200,255,.038) 1px,transparent 1px);
  background-size:52px 52px}
.bg-dots{position:absolute;inset:0;
  background-image:radial-gradient(rgba(0,200,255,.1) 1px,transparent 1px);
  background-size:26px 26px;opacity:.25}
.scan{position:absolute;left:0;right:0;height:180px;
  background:linear-gradient(transparent,rgba(0,200,255,.025),transparent);
  animation:scanH 14s linear infinite}
.clock-ring{position:absolute;width:760px;height:760px;border-radius:50%;
  top:50%;left:50%;transform:translate(-50%,-50%);
  border:1px solid rgba(0,200,255,.06)}
.clock-ring2{position:absolute;width:560px;height:560px;border-radius:50%;
  top:50%;left:50%;transform:translate(-50%,-50%);
  border:1px solid rgba(0,200,255,.04)}

/* NAV */
.nav{position:fixed;top:0;left:0;right:0;z-index:200;height:62px;padding:0 48px;
  display:flex;align-items:center;justify-content:space-between;
  background:rgba(1,6,15,.92);backdrop-filter:blur(24px);
  border-bottom:1px solid rgba(0,200,255,.14)}
.nav::after{content:'';position:absolute;bottom:0;left:0;right:0;height:1px;
  background:linear-gradient(90deg,transparent 0%,var(--blue) 40%,var(--purple) 70%,var(--gold) 90%,transparent 100%);
  opacity:.35}
.nav-logo{font-family:var(--hd);font-size:13px;font-weight:700;color:var(--white);
  letter-spacing:3px;cursor:pointer;line-height:1.3}
.nav-logo-sub{display:block;font-family:var(--mono);font-size:8px;color:var(--blue);letter-spacing:4px;opacity:.7}
.nav-arcana{font-family:var(--hd);font-size:10px;color:var(--gold);letter-spacing:3px;opacity:.65;
  border:1px solid rgba(255,215,0,.22);padding:3px 12px;
  clip-path:polygon(0 0,calc(100% - 6px) 0,100% 6px,100% 100%,6px 100%,0 calc(100% - 6px))}
.nav-links{display:flex;gap:2px}
.nl{position:relative;font-family:var(--mono);font-size:10px;color:var(--muted);padding:8px 14px;
  border:none;background:none;cursor:pointer;letter-spacing:2px;text-transform:uppercase;transition:var(--tr)}
.nl::after{content:'';position:absolute;bottom:0;left:50%;width:0;height:1px;
  background:var(--blue);transition:width .25s ease,left .25s ease}
.nl:hover,.nl.on{color:var(--blue)}
.nl:hover::after,.nl.on::after{width:100%;left:0}

/* PAGE */
.page{position:relative;z-index:1;padding-top:62px;min-height:100vh}

/* HERO */
.hero{min-height:calc(100vh - 62px);display:grid;grid-template-columns:1fr 440px;
  align-items:center;padding:60px 80px;gap:40px;position:relative}
.hero-text{}
.h-over{font-family:var(--mono);font-size:9px;color:var(--blue);letter-spacing:4px;
  text-transform:uppercase;margin-bottom:20px;display:flex;align-items:center;gap:10px;
  animation:fadeUp .5s .1s both}
.h-over::before{content:'';width:28px;height:1px;background:var(--blue);opacity:.7}
.hero-name{font-family:var(--hd);font-size:clamp(34px,4.5vw,58px);font-weight:900;
  line-height:1.05;color:var(--white);letter-spacing:.5px;margin-bottom:6px;animation:fadeUp .5s .2s both}
.hero-name .gold{color:var(--gold);text-shadow:var(--glow-gold)}
.hero-nick{font-family:var(--mono);font-size:13px;color:var(--blue);letter-spacing:5px;
  margin-bottom:28px;animation:fadeUp .5s .25s both}
.hero-role{font-family:var(--body);font-size:16px;font-weight:300;color:var(--muted);
  letter-spacing:3px;text-transform:uppercase;margin-bottom:18px;animation:fadeUp .5s .3s both}
.hero-about{font-family:var(--body);font-size:14px;line-height:1.85;
  color:rgba(232,244,255,.6);max-width:460px;margin-bottom:36px;animation:fadeUp .5s .35s both}

.sb-wrap{display:flex;flex-direction:column;gap:7px;margin-bottom:36px;animation:fadeUp .5s .4s both}
.sb-row{display:flex;align-items:center;gap:12px}
.sb-lbl{font-family:var(--mono);font-size:9px;color:var(--gold);letter-spacing:2px;width:28px;flex-shrink:0}
.sb-track{flex:1;height:4px;background:rgba(255,255,255,.06);border-radius:0;overflow:hidden}
.sb-fill{height:100%;border-radius:0}
.sb-hp{background:linear-gradient(90deg,#00c8ff,#0066dd);box-shadow:0 0 6px rgba(0,200,255,.5);width:87%}
.sb-sp{background:linear-gradient(90deg,#7b61ff,#cc44ff);box-shadow:0 0 6px rgba(123,97,255,.5);width:74%}
.sb-v{font-family:var(--mono);font-size:9px;color:var(--dim)}

.hero-btns{display:flex;gap:12px;flex-wrap:wrap;animation:fadeUp .5s .45s both}
.btn-p{display:inline-flex;align-items:center;gap:8px;padding:12px 26px;
  font-family:var(--mono);font-size:11px;letter-spacing:2px;text-transform:uppercase;
  cursor:pointer;border:none;background:transparent;color:var(--blue);position:relative;overflow:hidden;
  clip-path:polygon(0 0,calc(100% - 12px) 0,100% 12px,100% 100%,12px 100%,0 calc(100% - 12px));
  transition:var(--tr)}
.btn-p::before{content:'';position:absolute;inset:1px;
  background:linear-gradient(135deg,rgba(0,200,255,.1),rgba(123,97,255,.07));
  clip-path:polygon(0 0,calc(100% - 11px) 0,100% 11px,100% 100%,11px 100%,0 calc(100% - 11px))}
.btn-p::after{content:'';position:absolute;inset:0;border:1px solid rgba(0,200,255,.4);
  clip-path:polygon(0 0,calc(100% - 12px) 0,100% 12px,100% 100%,12px 100%,0 calc(100% - 12px))}
.btn-p span{position:relative;z-index:1}
.btn-p:hover{color:var(--white)}
.btn-p:hover::before{background:linear-gradient(135deg,rgba(0,200,255,.22),rgba(123,97,255,.18))}

.btn-s{display:inline-flex;align-items:center;gap:8px;padding:12px 26px;
  font-family:var(--mono);font-size:11px;letter-spacing:2px;text-transform:uppercase;
  cursor:pointer;background:transparent;color:var(--gold);
  border:1px solid rgba(255,215,0,.28);
  clip-path:polygon(0 0,calc(100% - 12px) 0,100% 12px,100% 100%,12px 100%,0 calc(100% - 12px));
  transition:var(--tr)}
.btn-s:hover{background:rgba(255,215,0,.08);border-color:var(--gold)}

/* PERSONA CARD */
.p-frame{position:relative;display:flex;align-items:center;justify-content:center;
  animation:float 5s ease-in-out infinite}
.p-ring1{position:absolute;width:390px;height:390px;border-radius:50%;
  border:1px solid rgba(0,200,255,.12);animation:spin 28s linear infinite;
  border-top-color:rgba(0,200,255,.55)}
.p-ring2{position:absolute;width:440px;height:440px;border-radius:50%;
  border:1px solid rgba(255,215,0,.07);animation:spinR 20s linear infinite;
  border-right-color:rgba(255,215,0,.38)}
.p-card{width:310px;height:420px;position:relative;overflow:hidden;
  background:linear-gradient(155deg,rgba(0,200,255,.07),rgba(123,97,255,.05),rgba(0,0,0,.25));
  border:1px solid rgba(0,200,255,.28);
  clip-path:polygon(0 0,calc(100% - 22px) 0,100% 22px,100% 100%,22px 100%,0 calc(100% - 22px));
  animation:fadeIn .8s .3s both}
.p-card-in{position:absolute;inset:5px;
  border:1px solid rgba(0,200,255,.1);
  clip-path:polygon(0 0,calc(100% - 18px) 0,100% 18px,100% 100%,18px 100%,0 calc(100% - 18px));
  display:flex;flex-direction:column;align-items:center;justify-content:center;
  gap:14px;padding:28px 20px}
.p-arcana{font-family:var(--hd);font-size:10px;font-weight:600;color:var(--gold);
  letter-spacing:5px;text-transform:uppercase;
  border-top:1px solid rgba(255,215,0,.28);border-bottom:1px solid rgba(255,215,0,.28);
  padding:4px 18px;margin-bottom:6px}
.p-symbol{font-size:64px;line-height:1;animation:moonGlow 3s ease-in-out infinite}
.p-cname{font-family:var(--hd);font-size:20px;font-weight:700;color:var(--white);
  letter-spacing:1px;text-align:center;text-shadow:0 0 16px rgba(0,200,255,.35)}
.p-cnick{font-family:var(--mono);font-size:12px;color:var(--blue);letter-spacing:4px}
.p-crole{font-family:var(--body);font-size:11px;font-weight:300;color:var(--muted);
  letter-spacing:2px;text-align:center;text-transform:uppercase}
.p-bar{width:100%;height:1px;background:linear-gradient(90deg,var(--blue),var(--purple),var(--gold));opacity:.4;margin-top:4px}
.p-dots{display:flex;gap:5px;margin-top:4px}
.p-dot{width:5px;height:5px;border-radius:50%;background:var(--blue);opacity:.3}
.p-dot.on{opacity:1;box-shadow:var(--glow)}
.p-tr1{position:absolute;top:-8px;right:52px;animation:pulse 3.5s infinite}
.p-tr2{position:absolute;bottom:16px;left:36px;animation:pulse 4s .8s infinite}

/* SECTION */
.sec{padding:80px 80px;position:relative}
.sec-tag{position:absolute;top:28px;left:48px;
  font-family:var(--mono);font-size:8px;color:rgba(0,200,255,.28);
  letter-spacing:3px;text-transform:uppercase;display:flex;align-items:center;gap:8px}
.sec-tag::before{content:'';width:16px;height:1px;background:rgba(0,200,255,.28)}
.sec-hd{margin-bottom:52px;display:flex;align-items:flex-end;gap:20px}
.sec-n{font-family:var(--hd);font-size:72px;font-weight:900;line-height:.85;
  color:rgba(0,200,255,.055);letter-spacing:-4px;user-select:none}
.sec-ht{}
.sec-ey{font-family:var(--mono);font-size:9px;color:var(--blue);
  letter-spacing:4px;text-transform:uppercase;margin-bottom:7px;display:block}
.sec-title{font-family:var(--hd);font-size:clamp(26px,3.2vw,42px);
  font-weight:700;color:var(--white);line-height:1.1}
.sec-title .dim{color:rgba(232,244,255,.2)}
.sec-rule{height:1px;margin-top:12px;
  background:linear-gradient(90deg,var(--blue),var(--purple),var(--gold),transparent);
  animation:barFill 1.2s .4s forwards;--w:200px;width:0}

/* SKILLS */
.sk-tabs{display:flex;gap:0;margin-bottom:40px;border-bottom:1px solid rgba(0,200,255,.12)}
.sk-tab{font-family:var(--mono);font-size:9px;letter-spacing:2px;text-transform:uppercase;
  color:var(--muted);padding:11px 22px;cursor:pointer;border:none;background:none;
  border-bottom:2px solid transparent;margin-bottom:-1px;transition:var(--tr);position:relative}
.sk-tab:hover{color:var(--blue)}
.sk-tab.on{color:var(--blue);border-bottom-color:var(--blue)}
.sk-tab.on::after{content:attr(data-arcana);position:absolute;top:-20px;left:50%;transform:translateX(-50%);
  font-family:var(--hd);font-size:7px;color:var(--gold);letter-spacing:2px;white-space:nowrap;opacity:.6}
.sk-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:11px}
.sk-card{background:rgba(5,13,31,.85);border:1px solid rgba(0,200,255,.1);
  padding:18px 20px;position:relative;overflow:hidden;
  clip-path:polygon(0 0,calc(100% - 13px) 0,100% 13px,100% 100%,13px 100%,0 calc(100% - 13px));
  transition:var(--tr);animation:fadeUp .5s both}
.sk-card::before{content:'';position:absolute;inset:0;
  background:linear-gradient(135deg,rgba(0,200,255,.04),transparent);opacity:0;transition:opacity .3s}
.sk-card:hover{border-color:rgba(0,200,255,.38);transform:translateY(-3px)}
.sk-card:hover::before{opacity:1}
.sk-tr{position:absolute;top:5px;right:5px;width:6px;height:6px;
  border-right:1px solid rgba(0,200,255,.28);border-top:1px solid rgba(0,200,255,.28)}
.sk-bl{position:absolute;bottom:5px;left:5px;width:6px;height:6px;
  border-left:1px solid rgba(0,200,255,.28);border-bottom:1px solid rgba(0,200,255,.28)}
.sk-top{display:flex;align-items:center;justify-content:space-between;margin-bottom:13px}
.sk-name{font-family:var(--body);font-size:14px;font-weight:600;color:var(--white)}
.sk-badge{font-family:var(--mono);font-size:8px;letter-spacing:1px;text-transform:uppercase;
  padding:2px 8px;
  clip-path:polygon(0 0,calc(100% - 5px) 0,100% 5px,100% 100%,5px 100%,0 calc(100% - 5px))}
.b-ex{background:rgba(0,200,255,.14);color:var(--blue)}
.b-ad{background:rgba(123,97,255,.14);color:var(--purple)}
.b-in{background:rgba(255,215,0,.1);color:var(--gold)}
.sk-track{height:3px;background:rgba(255,255,255,.05);overflow:hidden}
.sk-fill{height:100%;background:linear-gradient(90deg,var(--blue),var(--purple));
  box-shadow:0 0 5px rgba(0,200,255,.55);transition:width 1.3s cubic-bezier(.4,0,.2,1)}
.sk-pct{font-family:var(--mono);font-size:9px;color:rgba(0,200,255,.55);margin-top:5px;text-align:right}

/* EXP */
.exp-list{display:flex;flex-direction:column;gap:0;max-width:880px}
.exp-conn{width:1px;height:18px;background:linear-gradient(var(--blue),transparent);margin-left:32px}
.exp-card{position:relative;
  background:rgba(5,13,31,.85);border:1px solid rgba(0,200,255,.1);
  padding:26px 28px 26px 72px;
